// KI-Agenten Readiness Checklist Lead Magnet
const body = $input.first().json;
console.log('AI Checklist Lead Magnet Payload:', JSON.stringify(body));

const email =
  body.email ||
  body.Email ||
  body.subscriber?.email ||
  body.body?.email ||
  '';

if (!email || !email.includes('@')) {
  throw new Error(`Ungueltige Email im Payload: ${JSON.stringify(body)}`);
}

const firstName =
  body.firstname ||
  body.first_name ||
  body.vorname ||
  body.subscriber?.firstname ||
  body.body?.firstname ||
  'Business Leader';

const eventType = body.event || body.type || body.status || 'confirmed';

const downloadUrl = 'https://www.ai-engineering.at/downloads/ki-agenten-readiness-checklist.pdf';
const senderEmail = 'hallo@ai-engineering.at';
const senderName = 'Joe von AI-Engineering.at';

return [{
  json: {
    email: email.toLowerCase().trim(),
    firstName,
    eventType,
    downloadUrl,
    senderEmail,
    senderName,
    timestamp: new Date().toISOString()
  }
}];

